@Service
public class ElasticsearchProductSearchService {

    @Autowired
    private RestHighLevelClient client;

    @Value("${elasticsearch.index.name:products}")
    private String indexName;

    @Value("${elasticsearch.query.index.name:search_queries}")
    private String queryIndexName;

    public void createProductIndex() throws IOException {
        GetIndexRequest request = new GetIndexRequest(indexName);
        boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createRequest = new CreateIndexRequest(indexName);
            String mapping = "{\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"id\": {\"type\": \"keyword\"},\n" +
                    "      \"name\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                    "      \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                    "      \"price\": {\"type\": \"float\"},\n" +
                    "      \"category\": {\"type\": \"keyword\"},\n" +
                    "      \"brand\": {\"type\": \"keyword\"},\n" +
                    "      \"tags\": {\"type\": \"keyword\"},\n" +
                    "      \"inStock\": {\"type\": \"boolean\"},\n" +
                    "      \"createdAt\": {\"type\": \"date\", \"format\": \"yyyy-MM-dd HH:mm:ss\"}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}";
            createRequest.mapping(mapping, XContentType.JSON);
            client.indices().create(createRequest, RequestOptions.DEFAULT);
        }
    }

    public void createQueryIndex() throws IOException {
        GetIndexRequest request = new GetIndexRequest(queryIndexName);
        boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createRequest = new CreateIndexRequest(queryIndexName);
            String mapping = "{\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"query\": {\"type\": \"text\"},\n" +
                    "      \"timestamp\": {\"type\": \"date\", \"format\": \"yyyy-MM-dd HH:mm:ss\"},\n" +
                    "      \"userId\": {\"type\": \"keyword\"},\n" +
                    "      \"resultCount\": {\"type\": \"integer\"}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}";
            createRequest.mapping(mapping, XContentType.JSON);
            client.indices().create(createRequest, RequestOptions.DEFAULT);
        }
    }

    public IndexResponse indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(indexName);
        request.id(product.getId());
        String productJson = product.toJson();
        request.source(productJson, XContentType.JSON);
        return client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            IndexRequest request = new IndexRequest(indexName);
            request.id(product.getId());
            String productJson = product.toJson();
            request.source(productJson, XContentType.JSON);
            bulkRequest.add(request);
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new RuntimeException("Bulk indexing failed");
        }
    }

    public SearchResponse searchProducts(String query, int from, int size, Map<String, String> filters) throws IOException {
        SearchRequest searchRequest = new SearchRequest(indexName);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.from(from);
        searchSourceBuilder.size(size);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description").type("best_fields"));

        if (filters != null && !filters.isEmpty()) {
            for (Map.Entry<String, String> filter : filters.entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery(filter.getKey(), filter.getValue()));
            }
        }

        searchSourceBuilder.query(boolQuery);
        searchSourceBuilder.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC));

        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name");
        highlightBuilder.field("description");
        highlightBuilder.preTags("<mark>");
        highlightBuilder.postTags("</mark>");
        searchSourceBuilder.highlighter(highlightBuilder);

        searchRequest.source(searchSourceBuilder);

        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    public SearchResponse searchProductsWithFacets(String query, int from, int size, Map<String, String> filters, List<String> facetFields) throws IOException {
        SearchRequest searchRequest = new SearchRequest(indexName);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.from(from);
        searchSourceBuilder.size(size);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description").type("best_fields"));

        if (filters != null && !filters.isEmpty()) {
            for (Map.Entry<String, String> filter : filters.entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery(filter.getKey(), filter.getValue()));
            }
        }

        searchSourceBuilder.query(boolQuery);

        if (facetFields != null && !facetFields.isEmpty()) {
            for (String field : facetFields) {
                TermsAggregationBuilder aggregation = AggregationBuilders.terms(field + "_aggregation").field(field).size(100);
                searchSourceBuilder.aggregation(aggregation);
            }
        }

        searchRequest.source(searchSourceBuilder);

        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    public void saveSearchQuery(String query, String userId, int resultCount) throws IOException {
        ProductSearchQuery searchQuery = new ProductSearchQuery();
        searchQuery.setQuery(query);
        searchQuery.setUserId(userId);
        searchQuery.setResultCount(resultCount);
        searchQuery.setTimestamp(new Date());

        IndexRequest request = new IndexRequest(queryIndexName);
        String queryJson = searchQuery.toJson();
        request.source(queryJson, XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void updateProductStock(String productId, boolean inStock) throws IOException {
        UpdateRequest updateRequest = new UpdateRequest(indexName, productId);
        String script = "ctx._source.inStock = params.inStock";
        Map<String, Object> params = new HashMap<>();
        params.put("inStock", inStock);
        updateRequest.script(new org.elasticsearch.script.Script(script, params));
        UpdateResponse response = client.update(updateRequest, RequestOptions.DEFAULT);
    }

    public void updateProductPrice(String productId, double price) throws IOException {
        UpdateRequest updateRequest = new UpdateRequest(indexName, productId);
        String script = "ctx._source.price = params.price";
        Map<String, Object> params = new HashMap<>();
        params.put("price", price);
        updateRequest.script(new org.elasticsearch.script.Script(script, params));
        UpdateResponse response = client.update(updateRequest, RequestOptions.DEFAULT);
    }
}

